const { BEARER_TOKEN, API_KEY, ACCESS_TOKEN, API_SECRET_KEY, ACCESS_TOKEN_SECRET } = keys;
function generateOAuthParams(url, method) {
  const oauthParams = {
    oauth_consumer_key: API_KEY,
    oauth_nonce: crypto.randomBytes(16).toString('hex'),
    oauth_signature_method: 'HMAC-SHA1',
    oauth_timestamp: Math.floor(Date.now() / 1000).toString(),
    oauth_token: ACCESS_TOKEN,
    oauth_version: '1.0',
  };

  const baseString = [
    method.toUpperCase(),
    encodeURIComponent(url),
    encodeURIComponent(new URLSearchParams(oauthParams).toString()),
  ].join('&');

  const signingKey = `${API_SECRET_KEY}&${ACCESS_TOKEN_SECRET}`;
  oauthParams.oauth_signature = crypto.createHmac('sha1', signingKey).update(baseString).digest('base64');

  return oauthParams;
}

function buildOAuthHeader(oauthParams) {
  let header = 'OAuth ' + Object.keys(oauthParams)
    .map(key => `${encodeURIComponent(key)}="${encodeURIComponent(oauthParams[key])}"`)
    .join(', ');
  return header;
}

async function uploadMedia(i, fN, mT) {
  let url = 'https://upload.twitter.com/1.1/media/upload.json';
  let method = 'POST';
  let oauth = generateOAuthParams(url, method);
  let buffer = await this.helpers.getBinaryDataBuffer(i, 'data')
  let formData = new FormData();
  formData.append('media', buffer, { filename: fN, contentType: mT });
  let response = await fetch(url, {
    method: method,
    headers: {
      ...formData.getHeaders(),
      'Authorization': buildOAuthHeader(oauth),
    },
    body: formData,
  });
  console.log(response)
  if (!response.ok) {
    console.error('Failed to upload media:', await response.text());
    return null;
  }
  const data = await response.json();
  console.log("x media upload result: ", data)
  return data.media_id_string;
}

async function postTweet(text, mediaIds) {
  let url = 'https://api.twitter.com/2/tweets';
  let method = 'POST';
  let oauth = generateOAuthParams(url, method);
  const response = await fetch(url, {
    method: 'POST',
    headers: {
      // 'Authorization': `Bearer ${BEARER_TOKEN}`,
      'Authorization': buildOAuthHeader(oauth),
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      text: text,
      media: { media_ids: mediaIds }
    })
  });
  console.log('post tweet: ',response)
  if (!response.ok) {
    return null;
  }
  let res = await response.json()
  console.log('Tweet posted successfully:', res);
  return res;
}

